/* Tree traversal */
static inline float traverse_tree(int tree_id, const float* x) {
    const OptTree* tree = &TREES[tree_id];
    uint32_t node_idx = tree->start_idx;

    while (node_idx < tree->start_idx + tree->node_count) {
        const OptNode* node = &NODES[node_idx];

        if (node->is_leaf) {
            return SHARED_LEAVES[node->u.leaf_idx];
        }

        float threshold = decode_threshold(node->u.internal.threshold_q);

        if (x[node->u.internal.feature] < threshold) {
            node_idx = tree->start_idx + node->u.internal.left;
        } else {
            node_idx = tree->start_idx + node->u.internal.right;
        }
    }

    return 0.0f; /* unreachable */
}

void predict(const float* x, float* output) {
    for (int c = 0; c < N_CLASSES; c++) {
        output[c] = 0.500000f;
    }
    for (int i = 0; i < N_TREES; i++) {
        output[i % N_CLASSES] += traverse_tree(i, x);
    }
    /* Numerically stable softmax */
    float max_val = output[0];
    for (int c = 1; c < N_CLASSES; c++) {
        if (output[c] > max_val) max_val = output[c];
    }
    float sum = 0.0f;
    for (int c = 0; c < N_CLASSES; c++) {
        output[c] = expf(output[c] - max_val);
        sum += output[c];
    }
    for (int c = 0; c < N_CLASSES; c++) {
        output[c] /= sum;
    }
}

/* Returns the class index with the highest probability */
static inline int predict_class(const float* x) {
    float probs[N_CLASSES];
    predict(x, probs);
    int best = 0;
    for (int c = 1; c < N_CLASSES; c++) {
        if (probs[c] > probs[best]) best = c;
    }
    return best;
}

